mapper.sql:
and o.status != 0
and a.id = #{id}
and a.store_id = #{store_id}
and a.genre = #{genre}
and ( a.user_id like concat('%',#{user_name},'%') or
    c.zhanghao like concat('%',#{user_name},'%') or c.mobile like concat('%',#{user_name},'%'))

and a.from_id=#{from_id}

    
        #{type,jdbcType=INTEGER}
    

and a.add_date   >=   #{startDate}
and a.add_date   <=   #{endDate}
and a.user_level != 0 and a.user_level  is not null
and a.type = #{type}

mapper.select:
select a.id,a.user_id as gm_id,a.from_id as fx_id,a.status,a.type,a.money,a.sNo,a.event,a.level,a.user_level,a.type,a.add_date,a.genre,c.user_name as gm_name,c.mobile,c.zhanghao,c.headimgurl,g.sets from lkt_distribution_record as a left join lkt_user as c on a.user_id = c.user_id left join lkt_user_distribution as d on d.user_id = c.user_id left join lkt_distribution_grade as g on g.id = a.user_level left join lkt_order as o on a.sNo = o.sNo and o.status != 0
a.add_date ${add_date_sort},
limit #{pageStart},#{pageEnd}

SELECT a.user_id, a.p_name, a.num, a.img, a.attribute, a.user_name, a.order_status, a.add_time, a.z_price, a.sNo, a.otype, a.store_id, a.recycle FROM ( SELECT a.user_id, c.p_name, c.num, d.img, d.attribute, f.user_name, a.STATUS AS order_status, a.add_time, a.z_price, a.sNo, a.otype, a.store_id, a.recycle, ROW_NUMBER() over(partition by a.sNo) AS top FROM lkt_order AS a LEFT JOIN lkt_order_details AS c ON a.sNo = c.r_sNo LEFT JOIN lkt_configure AS d ON c.sid = d.id LEFT JOIN lkt_user AS f ON a.user_id = f.user_id
a.add_time ${add_time_sort},
) AS a
where a.top <2
limit #{pageStart},#{pageEnd}
